-- Plantilles de notificacions per al mòdul d'ofertes laborals i candidatures
	 -- Oferta laboral - Notificació - Tancament vençut i estat no tancat
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Exemple - Notificació - Oferta amb tancament vençut sense estat tancada', 'Plantilla per notificar al responsable que l''oferta té la data de tancament de candidatures d''ahir i no està en estat tancada o similar.', 'Revisar oferta laboral: tancament de candidatures vençut - $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_assigned_user_name,\r\n\r\nL''oferta laboral $stic_job_offers_name té la data de tancament de candidatures vençuda (ahir) i actualment està en estat $stic_job_offers_status.\r\n\r\nSi us plau, revisa l''oferta i actualitza''n l''estat si correspon: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_assigned_user_name,</p>\n<p>L''oferta laboral <strong>$stic_job_offers_name</strong> té la data de tancament de candidatures vençuda (ahir) i actualment està en estat <strong>$stic_job_offers_status</strong>.</p>\n<p>Si us plau, <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">revisa l''oferta</a> i actualitza''n l''estat si correspon.</p>', 0, '1', 0, 'notification'),
	-- Candidatura acceptada - Usuari assignat 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0001', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura acceptada - Usuari assignat ', 'Notifica a l''usuari assignat quan una candidatura passa a Acceptada, amb enllaç al CRM.', 'Candidatura acceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat Acceptada.\r\n\r\nLa pots revisar al CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_assigned_user_name,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha canviat a estat <strong>Acceptada</strong>.</p><p>La pots revisar al CRM: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Obrir candidatura al CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura acceptada - Candidat 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0002', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura acceptada - Candidat ', 'Notifica al candidat quan la seva candidatura passa a Acceptada, amb enllaç a l''àrea privada.', 'La teva candidatura ha estat acceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nEns complau informar-te que la teva candidatura per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha passat a estat Acceptada.\r\n\r\nPots consultar-ne el detall a la teva àrea privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:</p><p>Ens complau informar-te que la teva candidatura per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha passat a estat <strong>Acceptada</strong>.</p><p>Pots consultar-ne el detall a la teva àrea privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Accedir a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura acceptada - Organització 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0003', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura acceptada - Organització ', 'Notifica a l''organització quan una candidatura passa a Acceptada, amb enllaç a l''àrea privada.', 'Candidatura acceptada a l''oferta: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_account,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha passat a estat Acceptada.\r\n\r\nHo pots veure a l''àrea privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_account,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha passat a estat <strong>Acceptada</strong>.</p><p>Ho pots veure a l''àrea privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Accedir a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura rebutjada o tancada - Usuari assignat 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0010', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Usuari assignat', 'Notifica a l usuari l estat de descarte.', 'Candidatura rebutjada o tancada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\n\nT informem que s ha actualitzat l estat de la candidatura de $stic_job_applications_stic_job_applications_contacts_name per a la posició $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nL estat actual és: Candidatura descartada / Procés tancat.', '<p>Benvolgut/da <strong>$stic_job_applications_assigned_user_name</strong>,</p><p>T informem que s ha actualitzat l estat de la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a la posició <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>L estat actual és: <strong>Candidatura descartada / Procés tancat.</strong></p><p>Pots revisar el detall al CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Obrir candidatura al CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura rebutjada o tancada - Candidat 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0011', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Candidat', 'Notifica al candidat el descarte.', 'Actualització de la teva candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:\n\nMoltes gràcies per l interès en l oferta de $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nLamentem comunicar-te que en aquesta ocasió hem decidit avançar amb altres candidatures que s ajusten més als requisits actuals.', '<p>Benvolgut/da <strong>$stic_job_applications_stic_job_applications_contacts_name</strong>:</p><p>Moltes gràcies per l interès que has mostrat en la nostra oferta de <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>Després d una valoració detallada, lamentem comunicar-te que en aquesta ocasió hem decidit avançar amb altres candidatures que s ajusten més als requisits actuals.</p><p>Pots consultar l estat a la teva àrea privada: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Accedir a l àrea privada</a>.</p><p>Et desitgem molt d èxit. Atentament, $stic_job_applications_account</p>', 0, '1', 0, 'notification'),
	-- Candidatura rebutjada o tancada - Organització 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0012', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Organització', 'Notifica al compte el descarte.', 'Candidatura rebutjada o tancada a l oferta: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_account:\n\nLi comuniquem que la candidatura de $stic_job_applications_stic_job_applications_contacts_name per a la vacant de $stic_job_applications_stic_job_applications_stic_job_offers_name ha finalitzat la seva participació.', '<p>Benvolgut/da <strong>$stic_job_applications_account</strong>:</p><p>Li comuniquem que la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a la vacant de <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha finalizado su participación en el proceso.</p><p>Pot realitzar el seguiment a la seva àrea de client: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Accedir a l àrea privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura rebutjada/tancada - Usuari assignat
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0004', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Usuari assignat', 'Notifica a l''usuari assignat quan una candidatura passa a Rebutjada o tancada, amb enllaç al CRM.', 'Candidatura rebutjada o tancada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\n\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat Rebutjada o tancada.\n\nPots accedir al detall a: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n</head>\r\n<body>\r\n<p>Benvolgut/da <strong>$stic_job_applications_assigned_user_name</strong>,</p>\r\n<p>T''informem que s''ha actualitzat l''estat de la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a la posició <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p>\r\n<p>El nou estat és: <strong>Candidatura descartada / Procés tancat.</strong></p>\r\n<p>Pots revisar l''historial o els motius del descart directament al CRM mitjançant l''enllaç següent:</p>\r\n<p><a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Obrir candidatura al CRM</a></p>\r\n</body>\r\n</html>', 0, '1', 0, 'notification'),
	-- Candidatura altres estats - Usuari assignat 
